headStyles:
body {
  background: var(--dark-bg);
}

:root {
  --card-bg: #132d44;
  --card-border: #1a3a52;
  --text-gray: #a0b4c8;
  --text-dim: #6889a6;
}

.breadcrumb {
  max-width: 900px;
  margin: 1.5rem auto 0;
  padding: 0 2rem;
  font-size: 0.85rem;
  color: var(--text-dim);
}
.breadcrumb a {
  color: var(--text-gray);
  text-decoration: none;
}
.breadcrumb a:hover {
  color: var(--text-white);
}

.bill-hero {
  max-width: 900px;
  margin: 1rem auto 0;
  padding: 0 2rem 2rem;
  position: relative;
}
.bill-hero::after {
  content: "";
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 6px;
  background: var(--pride-gradient);
}
.bill-hero .bill-number {
  font-family: "Montserrat", sans-serif;
  font-size: 0.9rem;
  font-weight: 700;
  color: var(--text-dim);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 0.25rem;
}
.bill-hero h1 {
  font-family: "Montserrat", sans-serif;
  font-size: 2.2rem;
  font-weight: 800;
  margin-bottom: 0.25rem;
  color: var(--text-white);
}
.bill-hero .nickname {
  font-size: 1.1rem;
  color: var(--text-gray);
  margin-bottom: 0.5rem;
}
.bill-hero .official-title {
  font-size: 0.85rem;
  color: var(--text-dim);
  font-style: italic;
  margin-bottom: 1rem;
}
.bill-hero .badge-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  align-items: center;
  margin-bottom: 1rem;
}
.status-badge {
  padding: 0.3rem 0.8rem;
  border-radius: 4px;
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  font-family: "Montserrat", sans-serif;
}
@media (max-width: 768px) {
  .bill-hero h1 {
    font-size: 1.6rem;
  }
}

.detail-section {
  max-width: 900px;
  margin: 0 auto;
  padding: 2rem;
}
.detail-section h2 {
  font-family: "Montserrat", sans-serif;
  font-size: 1.3rem;
  font-weight: 700;
  margin-bottom: 1rem;
  padding-bottom: 0.5rem;
  border-bottom: 1px solid var(--card-border);
  color: var(--text-white);
}
.detail-section p {
  color: var(--text-gray);
  margin-bottom: 1rem;
  line-height: 1.7;
}
.detail-section ul {
  color: var(--text-gray);
  margin: 0 0 1rem 1.5rem;
}
.detail-section li {
  margin-bottom: 0.5rem;
  line-height: 1.6;
}

.meta-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  margin-bottom: 1.5rem;
}
.meta-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 8px;
  padding: 1rem;
}
.meta-card .meta-label {
  font-family: "Montserrat", sans-serif;
  font-size: 0.75rem;
  color: var(--text-dim);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 0.25rem;
}
.meta-card .meta-value {
  font-size: 0.95rem;
  color: var(--text-white);
}
@media (max-width: 768px) {
  .meta-grid {
    grid-template-columns: 1fr;
  }
}

/* Mobile responsiveness for bill detail */
@media (max-width: 768px) {
  .breadcrumb {
    padding: 0 1rem;
    margin-top: 1rem;
  }
  .bill-hero {
    padding: 0 1rem 1.5rem;
  }
  .detail-section {
    padding: 1.5rem 1rem;
  }
  .ext-links {
    flex-direction: column;
  }
  .ext-link {
    width: 100%;
    justify-content: center;
  }
  .cta-bar {
    padding: 0 1rem;
  }
}

.timeline-list {
  position: relative;
  padding-left: 1.5rem;
  border-left: 2px solid var(--card-border);
}
.timeline-item {
  position: relative;
  margin-bottom: 1.25rem;
  padding-left: 1rem;
}
.timeline-item::before {
  content: "";
  position: absolute;
  left: -1.75rem;
  top: 0.5rem;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--card-border);
}
.timeline-item.completed::before {
  background: #22c55e;
}
.timeline-item.current::before {
  background: #f59e0b;
  box-shadow: 0 0 8px rgba(245, 158, 11, 0.5);
}
.timeline-item .tl-date {
  font-family: "Montserrat", sans-serif;
  font-size: 0.8rem;
  color: var(--text-dim);
  font-weight: 600;
}
.timeline-item .tl-event {
  font-size: 0.95rem;
  color: var(--text-gray);
}

.ext-links {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  margin-top: 1rem;
}
.ext-link {
  display: none;
  align-items: center;
  gap: 0.4rem;
  padding: 0.5rem 1rem;
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 6px;
  font-size: 0.85rem;
  color: var(--text-gray);
  transition: all 0.2s;
  text-decoration: none;
}
.ext-link:hover {
  border-color: var(--dark-bg-lighter);
  color: var(--text-white);
}

.risk-card {
  background: linear-gradient(
    135deg,
    rgba(239, 68, 68, 0.08),
    rgba(239, 68, 68, 0.02)
  );
  border: 1px solid rgba(239, 68, 68, 0.15);
  border-radius: 8px;
  padding: 1.25rem;
  margin-bottom: 1rem;
}
.risk-card ul {
  margin-left: 1.25rem;
}

.cta-bar {
  max-width: 900px;
  margin: 0 auto 3rem;
  padding: 0 2rem;
}
.cta-inner {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 10px;
  padding: 1.5rem;
  text-align: center;
}
.cta-inner p {
  color: var(--text-gray);
  margin-bottom: 1rem;
}
.cta-inner a {
  display: inline-block;
  padding: 0.6rem 1.5rem;
  background: var(--color-blue);
  color: white;
  border-radius: 6px;
  font-weight: 600;
  font-size: 0.9rem;
  font-family: "Montserrat", sans-serif;
  transition: all 0.2s;
  text-decoration: none;
}
.cta-inner a:hover {
  background: #0039cc;
  transform: translateY(-1px);
}
